diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..ce1040f3bf14 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1367,8 +1367,73 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
     }
   }

-  if (V1 != V2)
+  if (V1 != V2) {
+    // If V1 != V2, check if one is (X & Mask) and the other is X.
+    // For example: (icmp ult X, C1) & (icmp eq (X & Mask), C2)
+    // If the range of X implied by the masked equality is a subset of the
+    // range satisfying the other comparison, we can simplify.
+    Value *X;
+    const APInt *Mask;
+    bool V1IsMasked = match(V1, m_And(m_Value(X), m_APInt(Mask))) && X == V2;
+    bool V2IsMasked = match(V2, m_And(m_Value(X), m_APInt(Mask))) && X == V1;
+    if ((V1IsMasked || V2IsMasked) &&
+        (V1IsMasked ? Pred1 : Pred2) == ICmpInst::ICMP_EQ) {
+      const APInt &MaskedC = V1IsMasked ? *C1 : *C2;
+      const APInt &OtherC = V1IsMasked ? *C2 : *C1;
+      CmpPredicate OtherPred = V1IsMasked ? Pred2 : Pred1;
+
+      // For (X & Mask) == MaskedC, the possible values of X are:
+      // min = MaskedC (when all masked-off bits are 0)
+      // max = MaskedC | ~Mask (when all masked-off bits are 1)
+      APInt MinX = MaskedC;
+      APInt MaxX = MaskedC | ~*Mask;
+
+      // Check if [MinX, MaxX] implies OtherPred with OtherC.
+      std::optional<bool> Implied;
+      switch (OtherPred) {
+      case ICmpInst::ICMP_ULT:
+        Implied = MaxX.ult(OtherC);
+        break;
+      case ICmpInst::ICMP_ULE:
+        Implied = MaxX.ule(OtherC);
+        break;
+      case ICmpInst::ICMP_UGT:
+        Implied = MinX.ugt(OtherC);
+        break;
+      case ICmpInst::ICMP_UGE:
+        Implied = MinX.uge(OtherC);
+        break;
+      case ICmpInst::ICMP_SLT:
+        Implied = MaxX.slt(OtherC);
+        break;
+      case ICmpInst::ICMP_SLE:
+        Implied = MaxX.sle(OtherC);
+        break;
+      case ICmpInst::ICMP_SGT:
+        Implied = MinX.sgt(OtherC);
+        break;
+      case ICmpInst::ICMP_SGE:
+        Implied = MinX.sge(OtherC);
+        break;
+      case ICmpInst::ICMP_EQ:
+        Implied = MinX == MaxX && MinX == OtherC;
+        break;
+      default:
+        break;
+      }
+
+      if (Implied && *Implied) {
+        // For AND: if masked implies other, result is the masked comparison
+        // (the more restrictive one).
+        // For OR: if masked implies other, result is the other comparison
+        // (the less restrictive one).
+        if (IsAnd)
+          return V1IsMasked ? ICmp1 : ICmp2;
+        return V1IsMasked ? ICmp2 : ICmp1;
+      }
+    }
     return nullptr;
+  }

   ConstantRange CR1 =
       MatchedAnd1

